#include<bits/stdc++.h>
using namespace std;
int n, m, a[21], dp[33334], num, k;
string s;
int main() {
	ios::sync_with_stdio(false);
	cin.tie(0) ; cout.tie(0);
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		for (int j = i; j <= 33333; j++) {
			dp[j] = max(dp[j], dp[j - i] + a[i]);
		}
	}
	cin >> m >> s;
	s = s + "#  ";
	for (int i = 0; i <= m+1; i++) {
		if (s[i] == 'a' && s[i + 1] == 'b' && s[i + 2] == 'c') {
			i += 2;
			k++;
		} else {
			num += dp[k];
			k = 0;
		}

	}
	cout << num;
	return 0;
}
